### Example of a Traditional Linked List Implementation

```javascript
class Node {
    /**
     * Creates a new Node.
     * @param {*} data - The data to be stored in the node.
     */
    constructor(data) {
        this.data = data;
        this.next = null;
    }
}

class LinkedList {
    /**
     * Creates a new LinkedList.
     */
    constructor() {
        this.head = null;
        this.size = 0;
    }

    /**
     * Adds a new item to the end of the linked list.
     * @param {*} item - The item to be added.
     */
    add(item) {
        const node = new Node(item);
        if (!this.head) {
            this.head = node;
        } else {
            let current = this.head;
            while (current.next) {
                current = current.next;
            }
            current.next = node;
        }
        this.size++;
    }

    /**
     * Removes an item at the specified index from the linked list.
     * @param {number} index - The index of the item to be removed.
     * @throws {Error} If the index is out of bounds.
     */
    remove(index) {
        if (index < 0 || index >= this.size) {
            throw new Error("Index out of bounds");
        }

        if (index === 0) {
            this.head = this.head.next;
        } else {
            let current = this.head;
            for (let i = 0; i < index - 1; i++) {
                current = current.next;
            }
            current.next = current.next.next;
        }
        this.size--;
    }

    /**
     * Gets the item at the specified index from the linked list.
     * @param {number} index - The index of the item to be retrieved.
     * @returns {*} The item at the specified index.
     * @throws {Error} If the index is out of bounds.
     */
    get(index) {
        if (index < 0 || index >= this.size) {
            throw new Error("Index out of bounds");
        }

        let current = this.head;
        for (let i = 0; i < index; i++) {
            current = current.next;
        }
        return current.data;
    }
}

